<?phpdefined('BASEPATH') OR exit('No direct script access allowed');class Session_management extends MY_Controller {    function __construct() {        parent::__construct();    }    public function index() {        $data['terms'] = returnTerms(array('keys' => 'id, term_name', 'format' => 'dropdown'));        $data['venues'] = returnVenues(array('keys' => 'id, venue_name', 'format' => 'dropdown'));        $data['clubs'] = returnClubs(array('keys' => 'id, club_name', 'format' => 'dropdown'));        $data['days'] = returnDays(array('keys' => 'id, day_name', 'format' => 'dropdown'));        $data['programs'] = returnPrograms(array('keys' => 'id,club_id, program_name', 'format' => 'dropdown'));        $data['sessions'] = $this->admin_manager->SelectAllQuery("SELECT 			s.`id`,			s.`session_name`,			c.`club_name`,			t.`term_name`,			p.`program_name`,			l.`level_name`,			v.`venue_name`,                        v.`short_code`			FROM			sessions s 			INNER JOIN `clubs` c 			ON s.`club_id` = c.`id` 			LEFT JOIN `levels` l 			ON l.`id` = s.`level_id`			INNER JOIN `programs` p 			ON p.`id` = s.`program_id` 			INNER JOIN `venues` v 			ON v.`id` = s.`venue_id` 			INNER JOIN `terms` t 			ON t.`id` = s.`term_id` ORDER BY s.id DESC", 'ARRAY');        loadViewComponents('session_management/session-management', $data);    }    public function create_session() {//        $data['date_picker'] = return_time_picker();        // $data['venues'] = returnVenues(array('keys' => 'id, venue_name', 'format' => 'dropdown'));        // $data['terms'] = returnTerms(array('keys' => 'id, term_name', 'format' => 'dropdown'));        // $data['clubs'] = returnClubs(array('keys' => 'id, club_name', 'format' => 'dropdown'));        // $data['programs'] = returnPrograms(array('keys' => 'id,club_id, program_name', 'format' => 'dropdown'));        // $data['levels'] = returnLevels(array('keys' => 'id,program_id, level_name', 'format' => 'dropdown'));        // $data['days_list'] = returnDays(array('keys' => 'id, day_name'));        $data['venues'] = returnVenues(array('keys' => 'id, venue_name', 'format' => 'dropdown'));        $data['terms'] = returnTerms(array('keys' => 'id, term_name', 'format' => 'dropdown'));        $data['clubs'] = returnClubs(array('keys' => 'id, club_name', 'format' => 'dropdown'));        $data['programs'] = returnPrograms(array('keys' => 'id,club_id, program_name', 'format' => 'dropdown'));        $data['levels'] = returnLevels(array('keys' => 'id,program_id, level_name', 'format' => 'dropdown'));        $data['days_list'] = returnDays(array('keys' => 'id, day_name', 'format' => 'dropdown'));        $data['staffs'] = $this->admin_manager->SelectAllQuery("SELECT u.* FROM users u INNER JOIN `staff` s ON u.`id`=s.`staff_id`", 'ARRAY');        // $data['session'] = $this->admin_manager->SelectByID('sessions', 'id', $id, 'ROW_A');        // $data['session_meta'] = $this->admin_manager->SelectByID('sessions_meta', 'session_id', $id, 'ARRAY');        loadViewComponents('session_management/session-creation', $data);    }    public function save_session() {        $daysNames = array("Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday");        $days = $this->input->post('day');        $club = $this->input->post('club');        $weekz = $this->input->post('weekz');        $levels = $this->input->post('level');        $response = false;        $level_name = $this->db->query("SELECT level_name,duration FROM levels WHERE id='{$levels}'")->row_array();        $duration = $level_name['duration'];        $session = array(            'session_name' => $this->input->post('session_name'),            'club_id' => $this->input->post('club'),            'venue_id' => $this->input->post('venues'),            'term_id' => $this->input->post('term'),            'program_id' => $this->input->post('program'),            'level_id' => $levels,            'insert_by' => '1',            'update_by' => '1',        );        $this->admin_manager->Insert('sessions', $session);        $insert_id = $this->db->insert_id();        if ($club != "4") {            if (!empty($days)) {                foreach ($days as $keys => $day) {                    $sessionMeta = array(                        'session_id' => $insert_id,                        'day_id' => $day,                        'day' => $this->input->post('day_name')[$keys],                        'start_time' => $this->input->post('starts_time')[$keys],                        'end_time' => $this->input->post('ends_time')[$keys],                        'open_to' => $this->input->post('program_areas')[$keys],                        'coach_id' => $this->input->post('staff')[$keys],                    );                    $this->admin_manager->Insert('sessions_meta', $sessionMeta);                }            }        } else {            if (!empty($weekz)) {                foreach ($weekz as $keys => $week) {                    $daysName = $this->getDaysname($this->input->post('start_datez')[$keys], $this->input->post('end_datez')[$keys]);                    $explode = explode(" ", $this->input->post('start_timez')[$keys]);                    $endtime = date('H:i', strtotime('+{$duration} minutes', strtotime($explode[0]))) . " " . $explode[1];                    if (!empty($daysName)) {                        foreach ($daysName as $daysN) {                            $sessions_meta_holiday = array(                                'session_id' => $insert_id,                                'week_id' => $week,                                'day_name' => $daysN['days'],//                                'day_id' => $daysNames[$daysN['days']],                                'start_date' => $this->input->post('start_datez')[$keys],                                'end_date' => $this->input->post('end_datez')[$keys],                                'start_time' => $this->input->post('start_timez')[$keys],                                'end_time' => $endtime,                                'exclusion_day_id' => $this->input->post('exclusion_days')[$keys],                            );                            $this->admin_manager->Insert('sessions_meta_holiday', $sessions_meta_holiday);                        }                    }                }            }        }        $msg = "Session Added Successfully!";        $this->session->set_flashdata("popup", "Session Added Successfully!");        redirect_to('/admin/session-management');    }    public function edit_session($id) {        $id = encrypt_decrypt('decrypt', $id);        $data['sessions'] = $this->db->query("SELECT 			s.`id`,			s.`session_name`,			c.`id` AS club_id,			t.`id` AS term_id,			p.`id` AS program_id,			l.`id` AS level_id,                        l.duration,			v.`id` AS venue_id,                        v.`short_code`			FROM			sessions s 			INNER JOIN `clubs` c 			ON s.`club_id` = c.`id`			INNER JOIN `levels` l 			ON l.`id` = s.`level_id`			INNER JOIN `programs` p 			ON p.`id` = s.`program_id` 			INNER JOIN `venues` v 			ON v.`id` = s.`venue_id` 			INNER JOIN `terms` t 			ON t.`id` = s.`term_id` WHERE s.id='$id'")->row_array();        $data['terms'] = returnTerms(array('keys' => 'id, term_name', 'format' => 'dropdown'), $data['sessions']['term_id']);        $data['venues'] = returnVenues(array('keys' => 'id, venue_name', 'format' => 'dropdown'), $data['sessions']['venue_id']);        $data['clubs'] = returnClubs(array('keys' => 'id, club_name', 'format' => 'dropdown'), $data['sessions']['club_id']);        $data['days'] = returnDays(array('keys' => 'id, day_name', 'format' => 'dropdown'));        $data['levels'] = returnLevels(array('keys' => '*', 'format' => 'dropdown'), $data['sessions']['level_id']);        $data['programs'] = returnPrograms(array('keys' => 'id,club_id, program_name', 'format' => 'dropdown'), $data['sessions']['program_id']);        $data['staffs'] = $this->admin_manager->SelectAllQuery("SELECT u.* FROM users u INNER JOIN `staff` s ON u.`id`=s.`staff_id`", 'ARRAY');        $data['session_id'] = $id;        loadViewComponents('session_management/edit-session', $data);    }    public function update_session() {        $days = $this->input->post('day');        $club = $this->input->post('club');        $weekz = $this->input->post('weekz');        $levels = $this->input->post('level');        $response = false;        $level_name = $this->db->query("SELECT level_name FROM levels WHERE id='{$levels}'")->row_array();        $duration = $level_name['duration'];        $session = array(            'session_name' => $this->input->post('session_name'),            'club_id' => $this->input->post('club'),            'venue_id' => $this->input->post('venues'),            'term_id' => $this->input->post('term'),            'program_id' => $this->input->post('program'),            'level_id' => $levels,            'insert_by' => '1',            'update_by' => '1',        );        $insert_id = $this->input->post('session_id');        $this->admin_manager->Update('sessions', $session, array('id' => $insert_id));        if ($club != "4") {            if (!empty($days)) {                $this->admin_manager->Delete('sessions_meta', 'session_id', $insert_id);                foreach ($days as $keys => $day) {                    $sessionMeta = array(                        'session_id' => $insert_id,                        'day_id' => $day,                        'day' => $this->input->post('day_name')[$keys],                        'start_time' => $this->input->post('starts_time')[$keys],                        'end_time' => $this->input->post('ends_time')[$keys],                        'open_to' => $this->input->post('program_areas')[$keys],                        'coach_id' => $this->input->post('staff')[$keys],                    );                    $this->admin_manager->Insert('sessions_meta', $sessionMeta);                }            }        } else {            if (!empty($weekz)) {                $this->admin_manager->Delete('sessions_meta_holiday', 'session_id', $insert_id);                foreach ($weekz as $keys => $week) {                    $explode = explode(" ", $this->input->post('start_timez')[$keys]);                    $endtime = date('H:i', strtotime('+{$duration} minutes', strtotime($explode[0]))) . " " . $explode[1];                    $sessions_meta_holiday = array(                        'session_id' => $insert_id,                        'week_id' => $week,                        'start_date' => $this->input->post('start_datez')[$keys],                        'end_date' => $this->input->post('end_datez')[$keys],                        'start_time' => $this->input->post('start_timez')[$keys],                        'end_time' => $endtime,                        'exclusion_day_id' => $this->input->post('exclusion_days')[$keys],                    );                    $this->admin_manager->Insert('sessions_meta_holiday', $sessions_meta_holiday);                }            }        }        $msg = "Session Edit Successfully!";        $this->session->set_flashdata("popup", "Session Added Successfully!");        redirect_to('/admin/session-management/edit_session/' . encrypt_decrypt('encrypt', $insert_id));    }//    public function update_session() {////        $session = array(//            'session_name' => $this->input->post('session_name'),//            'club_id' => $this->input->post('club'),//            'cost_per_session' => $this->input->post('cost_per_session'),//            'annual_reg_fee' => $this->input->post('annual_reg_free'),//            'competition_fee' => $this->input->post('competition_fee'),//            'full_week_cost' => $this->input->post('full_week_cost'),//            'session_card_cost' =>