ode(",", $this->input->post('document')[$key])[0];////                    $Base64Encoded = explode(",", $this->input->post('document')[$key])[1];////                    $levels['file_path'] = uploadFileHelper($Base64MIMI, $Base64Encoded);//                }////                $this->admin_manager->Insert('levels', $levels);//            }//        }//        $this->session->set_flashdata("popup", "Session has been updated successfully!");//        redirect_to('/admin/create-session');//    }    public function duplicationSession($id) {        $id = encrypt_decrypt('decrypt', $id);        $last_id = $this->DuplicateMySQLRecord('sessions', 'id', $id);        $CheckLevels = $this->admin_manager->SelectAll('levels', 'ROW_A', $params = 'COUNT(*) AS counts');        $CheckChildSession = $this->admin_manager->SelectAll('prog_child_sessions', 'ROW_A', $params = 'COUNT(*) AS counts');        if ($CheckLevels['counts'] > 0) {            $this->DuplicateMySQLRecord('levels', 'id', $id, 1, array('session_id' => $last_id));        }        if ($CheckChildSession['counts'] > 0) {            $this->DuplicateMySQLRecord('prog_child_sessions', 'id', $id, 1, array('session_id' => $last_id));        }        redirect_to('/admin/session-management');    }    public function DuplicateMySQLRecord($table, $primary_key_field, $primary_key_val, $extra = '', $param = array()) {        /* generate the select query */        $this->db->where($primary_key_field, $primary_key_val);        $query = $this->db->get($table);        foreach ($query->result() as $row) {            foreach ($row as $key => $val) {                if ($key != $primary_key_field) {                    /* $this->db->set can be used instead of passing a data array directly to the insert or update functions */                    @$this->db->set($key, $val);                }//endif                          }//endforeach        }//endforeach        /* insert the new record into table */        if (empty($extra)) {            $this->db->insert($table);        } else {            @$this->db->set($param);            $this->db->insert($table);        }        return $this->db->insert_id();    }    public function delete_session($id) {        $id = encrypt_decrypt('decrypt', $id);        $this->admin_manager->Delete('sessions', 'id', $id);        redirect_to('admin/session-management');    }    public function getbyparams() {        $value = $this->input->post('value');        $key = $this->input->post('key');        $table = $this->input->post('table');        $query = "SELECT * FROM $table WHERE $key='$value'";        $data = $this->db->query($query)->result_array();        return print_r(json_encode($data));    }    public function getProgramclubs() {        echo returnPrograms(array('keys' => 'id, program_name', 'where' => array("club_id='{$this->input->post('club_id')}'"), 'format' => 'dropdown'));    }    public function getProgramLevels() {        echo returnLevels(array('keys' => 'id, level_name,duration', 'where' => array("program_id='{$this->input->post('program_id')}'"), 'format' => 'dropdown'));    }    public function getSession() {        $days = array("", "Sunday", "Monday", "Tuesday", "Wednesday", "Thrusday", "Friday", "Saturday");        $weeks = array("", "Week 1", "Week 2", "Week 3", "Week 4", "Week 5", "Week 6", "Week 7");        $programAreas = array("", "Open to All", "Venue Only");        $session_id = $this->input->post("session_id");        $venue_db = $this->db->query("SELECT * FROM `sessions` WHERE id='{$session_id}'")->row_array();        $table = '';        if ($venue_db['club_id'] != "4") {            $sessions_dbs = $this->db->query("SELECT     			sm.*,u.`username`     			FROM    			`sessions_meta` sm     			LEFT JOIN `users` u     			ON u.`id` = sm.`coach_id`     			WHERE session_id='{$session_id}'")->result_array();            $table .= '<div class="seprapte col-md-12">';            $table .= '<table class="table">';            $table .= '<thead>';            $table .= '<tr>';            $table .= '<th>Day</th>';            $table .= '<th>Date</th>';            $table .= '<th>Start Time</th>';            $table .= '<th>End Time</th>';            $table .= '<th>Program Area</th>';            $table .= '<th>Coach</th>';            $table .= '</tr>';            $table .= '</thead>';            $table .= '<tbody>';            foreach ($sessions_dbs as $sessions_db) {                $table .= '<tr>';                $table .= '<td>' . $days[$sessions_db['day_id']] . '</td>';                $table .= '<td>' . $sessions_db['date'] . '</td>';                $table .= '<td>' . $sessions_db['start_time'] . '</td>';                $table .= '<td>' . $sessions_db['end_time'] . '</td>';                $table .= '<td>' . $programAreas[$sessions_db['open_to']] . '</td>';                $table .= '<td>' . $sessions_db['username'] . '</td>';                $table .= '</tr>';            }            $table .= '</tbody>';            $table .= '</table>';            $table .= '</div>';            $table .= '</div>';        } else {            $sessions_dbs = $this->db->query("SELECT * FROM `sessions_meta_holiday` WHERE session_id='{$session_id}'")->result_array();            $table .= '<div class="seprapte col-md-12">';            $table .= '<table class="table">';            $table .= '<thead>';            $table .= '<tr>';            $table .= '<th>Week</th>';            $table .= '<th>Start Date</th>';            $table .= '<th>End Date</th>';            $table .= '<th>Start Time</th>';            // $table .= '<th>End Time</th>';            $table .= '<th>Exclusive Day ID</th>';            $table .= '</tr>';            $table .= '</thead>';            $table .= '<tbody>';            foreach ($sessions_dbs as $sessions_db) {                $table .= '<tr>';                $table .= '<td>' . $weeks[$sessions_db['week_id']] . '</td>';                $table .= '<td>' . $sessions_db['start_date'] . '</td>';                $table .= '<td>' . $sessions_db['end_date'] . '</td>';                $table .= '<td>' . $sessions_db['start_time'] . '</td>';                // $table .= '<td>'.$sessions_db['end_time'].'</td>';                $table .= '<td>' . $days[$sessions_db['exclusion_day_id']] . '</td>';                $table .= '</tr>';            }            $table .= '</tbody>';            $table .= '</table>';            $table .= '</div>';            $table .= '</div>';        }        echo $table;    }    public function filter_sessions() {        $term_id = $this->input->post('term_id');        $club_id = $this->input->post('club_id');        $program_id = $this->input->post('program_id');        $level_id = $this->input->post('level_id');        $venue_id = $this->input->post('venue_id');        $where = '';        if (!empty($term_id)) {            $where .= " AND s.term_id='$term_id'";        }        if (!empty($club_id)) {            $where .= " AND s.club_id='$club_id'";        }        if (!empty($program_id)) {            $where .= " AND s.program_id='$program_id'";        }        if (!empty($level_id)) {            $where .= " AND s.level_id='$level_id'";        }        if (!empty($venue_id)) {            $where .= " AND s.venue_id='$venue_id'";        }        $sessions = $this->admin_manager->SelectAllQuery("SELECT 			s.`id`,			s.`session_name`,			c.`club_name`,			t.`term_name`,			p.`program_name`,			l.`level_name`,			v.`venue_name`,                        v.`short_code`			FROM			sessions s 			INNER JOIN `clubs` c 			ON s.`club_id` = c.`id` 			INNER JOIN `levels` l 			ON l.`id` = s.`level_id`			INNER JOIN `programs` p 			ON p.`id` = s.`program_id` 			INNER JOIN `venues` v 			ON v.`id` = s.`venue_id` 			INNER JOIN `terms` t 			ON t.`id` = s.`term_id` WHERE s.status='1' $where", 'ARRAY');        if (!empty($sessions)) {            foreach ($sessions as $session) {                ?>                <tr>                    <td class="mdl-data-table__cell--non-numeric"><?php echo $session['session_name']; ?></td>                    <td class="mdl-data-table__cell--non-numeric"><?php echo $session['term_name']; ?></td>                    <td><?php echo $session['club_name']; ?></td>                    <td><?php echo $session['program_name']; ?></td>                    <td><?php echo $session['level_name']; ?></td>                    <td><?php echo $session['short_code']; ?></td>                    <td class="actions">                        <a href="<?php print_url('/admin/session-management/session-info/' . encrypt_decrypt('encrypt', $session['id'])); ?>" title="Info">                            <i class="material-icons f-left">info</i>                        </a>                        <a href="<?php print_url('/admin/session-management/edit_session/' . encrypt_decrypt('encrypt', $session['id'])); ?>" class="" data-toggle="tooltip" title="Session">                            <i class="material-icons f-left">edit</i>                        </a>                        <a href="#myModal" class="delete_me" data-href="<?php print_url('/admin/session-management/delete_session/' . encrypt_decrypt('encrypt', $session['id'])); ?>"  data-toggle="modal" title="Delete">                            <i class="material-icons f-left">delete</i>                        </a>                    </td>                </tr>                <?php            }        } else {            ?>            <tr><td colspan="6"><center><i>No Records Found</i></center></td></tr>            <?php        }    }    public function check_session() {        $data = array();        $table = '';        //==========================================        $day_id = $this->input->post("day_id");        $start_time = $this->input->post("start_time");        $end_time = $this->input->post("end_time");        $coach_id = $this->input->post("coach_id");        $class = $this->input->post("class");        //============================================        $startDate = $this->input->post("startDate");        $endDate = $this->input->post("endDate");        $start_time = $this->input->post("start_time");        $end_time = $this->input->post("end_time");        $exclusion_day = $this->input->post("exclusion_day");        $week_id = $this->input->post("week_id");        if ($class == 'day') {            $data = array(                'day_id' => $day_id,                'start_time' => $start_time,                'end_time' => $end_time,                'coach_id' => $coach_id,            );            $table = 'sessions_meta';        } else if ($class == "week") {            $data = array(                'week_id' => $week_id,                'start_date' => $startDate,                'end_date' => $endDate,                'start_time' => $start_time,                'end_time' => $end_time,                'exclusion_day_id' => $exclusion_day,            );            $table = 'sessions_meta_holiday';        }        $query = $this->admin_manager->CompareColumns($table, $data);        if (!empty($query)) {            echo "1";        } else {            echo "0";        }    }    public function session_info($id) {        $id = encrypt_decrypt('decrypt', $id);        $days = array("", "Sunday", "Monday", "Tuesday", "Wednesday", "Thrusday", "Friday", "Saturday");        $weeks = array("", "Week 1", "Week 2", "Week 3", "Week 4", "Week 5", "Week 6", "Week 7");        $programAreas = array("", "Open to All", "Venue Only");        $data['sessions'] = $this->db->query("SELECT 			s.`id`,                        c.id AS club_id,			s.`session_name`,			c.`club_name`,			t.`term_name`,			p.`program_name`,			l.`level_name`,			v.`venue_name`,                        v.`short_code`			FROM			sessions s 			INNER JOIN `clubs` c 			ON s.`club_id` = c.`id` 			INNER JOIN `levels` l 			ON l.`id` = s.`level_id`			INNER JOIN `programs` p 			ON p.`id` = s.`program_id` 			INNER JOIN `venues` v 			ON v.`id` = s.`venue_id` 			INNER JOIN `terms` t 			ON t.`id` = s.`term_id`                        WHERE s.id='$id'")->row_array();        ob_start();        if ($data['sessions']['club_id'] == 4) {            $sessions_dbs = $this->db->query("SELECT * FROM `sessions_meta_holiday` WHERE session_id='{$id}'")->result_array();            ?>            <table class="table">                <thead>                    <tr>                        <th>Week</th>                        <th>Start Date</th>                        <th>End Date</th>                        <th>Start Time</th>                        <th>End Time</th>                        <th>Exclusive Day ID</th>                    </tr>                </thead>                <tbody>                    <?php foreach ($sessions_dbs as $sessions_db) { ?>                        <tr>                            <td> <?= $weeks[$sessions_db['week_id']] ?> </td>                            <td> <?= $sessions_db['start_date'] ?> </td>                            <td> <?= $sessions_db['end_date'] ?> </td>                            <td> <?= $sessions_db['start_time'] ?> </td>                            <td> <?= $sessions_db['end_time'] ?> </td>                            <td> <?= $days[$sessions_db['exclusion_day_id']] ?> </td>                        </tr>                    <?php }                    ?>                </tbody>            </table>            <?php        } else {            $sessions_dbs = $this->db->query("SELECT sm.*,u.username FROM `sessions_meta` sm LEFT JOIN users u ON sm.coach_id=u.id WHERE session_id='{$id}'")->result_array();            ?>            <table class="table">                <thead>                    <tr>                        <th>Day</th>                        <th>Start Time</th>                        <th>End Time</th>                        <th>Program Area</th>                        <th>Coach</th>                    </tr>                </thead>                <tbody>                    <?php foreach ($sessions_dbs as $sessions_db) { ?>                        <tr>                            <td> <?= $days[$sessions_db['day_id']] ?> </td>                            <td> <?= $sessions_db['start_time'] ?> </td>                            <td> <?= $sessions_db['end_time'] ?> </td>                            <td> <?= $programAreas[$sessions_db['open_to']] ?> </td>                            <td> <?= $sessions_db['username'] ?> </td>                        </tr>                    <?php }                    ?>                </tbody>            </table>            <?php        }        $data['html'] = ob_get_clean();        loadViewComponents('session_management/session_info', $data);    }    public function getSessionInfo() {        $session_id = $this->input->post('session_id');        $week_id = $this->input->post('week_id');        $days = array("", "Sunday", "Monday", "Tuesday", "Wednesday", "Thrusday", "Friday", "Saturday");        $query = $this->db->query("SELECT * FROM sessions_meta_holiday WHERE session_id='$session_id' AND week_id='$week_id'")->result_array();        ob_start();        if (!empty($query)) {            foreach ($query as $q) {                ?>                <div class="row result-assessment">                    <div class="col-lg-6">                        <span class="mdl-chip mdl-chip--deletable">                            <span class="mdl-chip__text"                                  ><span class="time">WEEK<?= $q['week_id'] ?> |                                     <input type="hidden" name="weekz[]" value="<?= $q['week_id'] ?>">                                     <?= $days[$q['exclusion_day_id']] ?> | <input type="hidden" name="exclusion_days[]" value="<?= $q['exclusion_day_id']; ?>">                                    <?= $q['start_date'] ?> <input type="hidden" name="start_datez[]" value="<?= $q['start_date'] ?>">                                    - <?= $q['end_date'] ?><input type="hidden" name="end_datez[]" value="<?= $q['end_date'] ?>">                                     - <?= $q['start_time'] ?>  <input type="hidden" name="start_timez[]" value="<?= $q['start_time'] ?>">                                    - <?= $q['end_time'] ?><input type="hidden" name="end_timez[]" value="<?= $q['end_time'] ?>">                                </span>                            </span>                            <button type="button" class="mdl-chip__action closeme">                                <i class="material-icons">cancel</i>                            </button>                        </span>                    </div>                </div>                <?php            }        }        $html = ob_get_clean();        echo $html;    }    public function getSessionResult($day_id, $sessionid = '') {        $query = $this->db->query("SELECT sm.*,u.username FROM `sessions_meta` sm INNER JOIN users u ON u.`id`= sm.`coach_id` WHERE sm.day_id='$day_id' AND session_id='$sessionid'")->result_array();        $programAreas = array("", "Open to All", "Venue Only");        ob_start();        if (!empty($query)) {            foreach ($query as $q) {                ?>                <div class="col-lg-6">                    <span class="mdl-chip mdl-chip--deletable">                        <span class="mdl-chip__text">                            <span class="time"><?= $q['day'] ?>                                 <input type="hidden" name="day[]" value="<?= $q['day_id'] ?>">                                <input type="hidden" name="day_name[]" value="<?= $q['day'] ?>"> <?= $programAreas[$q['open_to']] ?>|                                 <input type="hidden" name="program_areas[]" value="<?= $q['open_to'] ?>">  <?= $q['username'] ?>                                 <input type="hidden" name="staff[]" value="<?= $q['coach_id'] ?>">  - <?= $q['start_time'] ?>                                <input type="hidden" name="starts_time[]" value="<?= $q['start_time'] ?>"> - <?= $q['end_time'] ?>                                <input type="hidden" name="ends_time[]" value="<?= $q['end_time'] ?>">                            </span>                        </span>                        <button type="button" class="mdl-chip__action closeme">                            <i class="material-icons">cancel</i>                        </button>                    </span>                </div>                <?php            }        }        $html = ob_get_clean();        return $html;    }    public function getDaysname($startDate, $endDate) {        $sql = $this->db->query("SELECT             *            FROM              (SELECT               DAYNAME(ADDDATE(                  '1970-01-01',                  t4 * 10000 + t3 * 1000 + t2 * 100 + t1 * 10 + t0                )) AS days,                ADDDATE(                  '1970-01-01',                  t4 * 10000 + t3 * 1000 + t2 * 100 + t1 * 10 + t0                ) selected_date               FROM                (SELECT                   0 t0                 UNION                SELECT                   1                 UNION                SELECT                   2                 UNION                SELECT                   3                 UNION                SELECT                   4                 UNION                SELECT                   5                 UNION                SELECT                   6                 UNION                SELECT                   7                 UNION                SELECT                   8                 UNION                SELECT                   9) t0,                (SELECT                   0 t1                 UNION                SELECT                   1                 UNION                SELECT                   2                 UNION                SELECT                   3                 UNION                SELECT                   4                 UNION                SELECT                   5                 UNION                SELECT                   6                 UNION                SELECT                   7                 UNION                SELECT                   8                 UNION                SELECT                   9) t1,                (SELECT                   0 t2                 UNION                SELECT                   1                 UNION                SELECT                   2                 UNION                SELECT                   3                 UNION                SELECT                   4                 UNION                SELECT                   5                 UNION                SELECT                   6                 UNION                SELECT                   7                 UNION                SELECT                   8                 UNION                SELECT                   9) t2,                (SELECT                   0 t3                 UNION                SELECT                   1                 UNION                SELECT                   2                 UNION                SELECT                   3                 UNION                SELECT                   4                 UNION                SELECT                   5                 UNION                SELECT                   6                 UNION                SELECT                   7                 UNION                SELECT                   8                 UNION                SELECT                   9) t3,                (SELECT                   0 t4                 UNION                SELECT                   1                 UNION                SELECT                   2                 UNION                SELECT                   3                 UNION                SELECT                   4                 UNION                SELECT                   5                 UNION                SELECT                   6                 UNION                SELECT                   7                 UNION                SELECT                   8                 UNION                SELECT                   9) t4) v             WHERE selected_date BETWEEN DATE_FORMAT(                STR_TO_DATE('{$startDate}', '%d-%m-%Y'),                '%Y-%m-%d'              )               AND DATE_FORMAT(                STR_TO_DATE('{$endDate}', '%d-%m-%Y'),                '%Y-%m-%d'              )")->result_array();        return $sql;    }}